import React, { useState, useEffect } from 'react';
import { ShoppingCart, MapPin, Search, Globe } from 'lucide-react';
import { dbSimulador } from '../services/dbSimulador';

const PanelCliente = () => {
  const [todasLasOfertas, setTodasLasOfertas] = useState([]);
  const [ofertasFiltradas, setOfertasFiltradas] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  
  const [provinciaSel, setProvinciaSel] = useState('Tucumán');
  const [ciudadSel, setCiudadSel] = useState('Todas');
  const [zonaSel, setZonaSel] = useState('Todas las zonas');

  useEffect(() => {
    const datos = dbSimulador.getOfertasGlobales();
    setTodasLasOfertas(datos);
  }, []);

  useEffect(() => {
    const resultado = todasLasOfertas.filter(o => {
      const matchBusqueda = o.producto.toLowerCase().includes(busqueda.toLowerCase());
      const matchProv = o.provincia === provinciaSel;
      const matchCiudad = ciudadSel === 'Todas' || o.ciudad === ciudadSel;
      const matchZona = zonaSel === 'Todas las zonas' || o.zona === zonaSel;
      return matchBusqueda && matchProv && matchCiudad && matchZona;
    });
    setOfertasFiltradas(resultado);
  }, [busqueda, provinciaSel, ciudadSel, zonaSel, todasLasOfertas]);

  // Listas dinámicas basadas en lo que hay en la "base de datos"
  const provincias = [...new Set(todasLasOfertas.map(o => o.provincia))];
  const ciudades = [...new Set(todasLasOfertas.filter(o => o.provincia === provinciaSel).map(o => o.ciudad))];
  const zonas = ['Todas las zonas', ...new Set(todasLasOfertas.filter(o => o.ciudad === ciudadSel || ciudadSel === 'Todas').map(o => o.zona))];

  return (
    <div style={{ background: '#f4f7f6', minHeight: '100vh' }}>
      <div style={navUbicacion}>
        <div style={contenedorUbi}>
          <div style={ubiGroup}>
            <Globe size={18} color="#e67e22" />
            <div style={selectBox}>
              <label style={miniLabel}>Provincia</label>
              <select value={provinciaSel} onChange={(e) => {setProvinciaSel(e.target.value); setCiudadSel('Todas');}} style={selectEstilo}>
                {provincias.length > 0 ? provincias.map(p => <option key={p} value={p}>{p}</option>) : <option>Tucumán</option>}
              </select>
            </div>
          </div>
          <div style={divisorV} />
          <div style={ubiGroup}>
            <MapPin size={18} color="#e67e22" />
            <div style={selectBox}>
              <label style={miniLabel}>Ciudad</label>
              <select value={ciudadSel} onChange={(e) => setCiudadSel(e.target.value)} style={selectEstilo}>
                <option value="Todas">Todas las ciudades</option>
                {ciudades.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
          </div>
        </div>

        <div style={zonaWrapper}>
          <div style={zonaScroll}>
            {zonas.map(z => (
              <button key={z} onClick={() => setZonaSel(z)} style={zonaSel === z ? zonaBtnActive : zonaBtn}>{z}</button>
            ))}
          </div>
        </div>
      </div>

      <div style={{ padding: '20px 5%' }}>
        <div style={searchContainer}>
          <Search size={20} color="#94a3b8" />
          <input type="text" placeholder="¿Qué estás buscando?" style={inputBusqueda} onChange={(e) => setBusqueda(e.target.value)} />
        </div>

        <div style={gridPro}>
          {ofertasFiltradas.map(o => (
            <div key={o.id} style={cardPro}>
              <div style={ahorroBadge}>-{Math.round(((o.precioViejo - o.precioNuevo)/o.precioViejo)*100)}%</div>
              <div style={cuerpoCard}>
                <p style={localTag}>{o.nombreLocal} • {o.zona}</p>
                <h4 style={prodTitle}>{o.producto}</h4>
                <p style={ubiDetalle}><MapPin size={12} /> {o.direccionLocal}, {o.ciudad}</p>
                <div style={priceContainer}>
                  <span style={priceMain}>${o.precioNuevo}</span>
                  <span style={priceOff}>${o.precioViejo}</span>
                </div>
                <button style={btnComprarPro}><ShoppingCart size={18} /> Reservar</button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

// Estilos (Resumidos para brevedad, mantener los que ya tenías de diseño pro)
const navUbicacion = { background: 'white', padding: '15px 5%', borderBottom: '1px solid #e2e8f0', position: 'sticky', top: 0, zIndex: 1000 };
const contenedorUbi = { display: 'flex', alignItems: 'center', background: '#f8fafc', borderRadius: '12px', padding: '10px 15px', marginBottom: '15px' };
const ubiGroup = { display: 'flex', alignItems: 'center', gap: '10px', flex: 1 };
const selectBox = { display: 'flex', flexDirection: 'column' };
const miniLabel = { fontSize: '0.6rem', color: '#94a3b8', fontWeight: 'bold' };
const selectEstilo = { border: 'none', background: 'transparent', fontSize: '0.9rem', fontWeight: 'bold', outline: 'none' };
const divisorV = { width: '1px', height: '25px', background: '#e2e8f0', margin: '0 15px' };
const zonaWrapper = { overflow: 'hidden' };
const zonaScroll = { display: 'flex', gap: '10px', overflowX: 'auto', paddingBottom: '10px' };
const zonaBtn = { padding: '8px 16px', borderRadius: '20px', border: '1px solid #e2e8f0', background: 'white', whiteSpace: 'nowrap', flexShrink: 0, cursor: 'pointer' };
const zonaBtnActive = { ...zonaBtn, background: '#1e293b', color: 'white' };
const searchContainer = { display: 'flex', alignItems: 'center', gap: '10px', background: 'white', padding: '15px', borderRadius: '15px', border: '1px solid #e2e8f0' };
const inputBusqueda = { border: 'none', outline: 'none', flex: 1 };
const gridPro = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '20px', marginTop: '20px' };
const cardPro = { background: 'white', borderRadius: '20px', border: '1px solid #e2e8f0', position: 'relative' };
const ahorroBadge = { position: 'absolute', top: '15px', right: '15px', background: '#ef4444', color: 'white', padding: '4px 8px', borderRadius: '8px', fontWeight: 'bold' };
const cuerpoCard = { padding: '20px' };
const localTag = { fontSize: '0.7rem', color: '#e67e22', fontWeight: 'bold' };
const ubiDetalle = { fontSize: '0.75rem', color: '#64748b', display: 'flex', alignItems: 'center', gap: '4px', margin: '5px 0' };
const prodTitle = { fontSize: '1.1rem', margin: '10px 0' };
const priceContainer = { display: 'flex', alignItems: 'baseline', gap: '8px' };
const priceMain = { fontSize: '1.8rem', fontWeight: 'bold' };
const priceOff = { fontSize: '0.9rem', textDecoration: 'line-through', color: '#94a3b8' };
const btnComprarPro = { width: '100%', padding: '12px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '12px', marginTop: '15px', cursor: 'pointer', display: 'flex', justifyContent: 'center', gap: '8px' };

export default PanelCliente;
